const data = items[0].json;
const query = data.query || {};

// ---- берём сырые данные ----
// если оставишь только { data: { expenditures, revenues, ... } } – этого достаточно
const src = data.data || data;          // ★ так будет работать и со старой, и с новой схемой
const rawExp = Array.isArray(src.expenditures) ? src.expenditures : [];
const rawRev = Array.isArray(src.revenues) ? src.revenues : [];

// ---- month dictionaries & order ----
const monthMap = {
  january:'Январь', february:'Февраль', march:'Март', april:'Апрель',
  may:'Май', june:'Июнь', july:'Июль', august:'Август',
  september:'Сентябрь', october:'Октябрь', november:'Ноябрь', december:'Декабрь',
};
const engMonthsInOrder = [
  'january','february','march','april','may','june',
  'july','august','september','october','november','december'
];

// ---- selection from query / default ----
let monthParam = (query.month || data.month || '').toString().trim().toLowerCase();
let yearParam  = (query.year || '').toString().trim();
const now = new Date();
if (!monthParam) monthParam = now.toLocaleString('en-US', { month:'long' }).toLowerCase();
if (!yearParam) yearParam = String(now.getFullYear());

// ---- build availability from data_available (если удалишь — просто будет пусто) ----
const files = Array.isArray(data.data_available) ? data.data_available : [];
const availability = {};
for (const f of files) {
  const m = f.match(/^([a-zA-Z]+)_(\d{4})\.json$/i);
  if (!m) continue;
  const eng = m[1].toLowerCase();
  const yr  = m[2];
  if (!availability[yr]) availability[yr] = new Set();
  availability[yr].add(eng);
}
const availableYears = Object.keys(availability).sort();
if (!availability[yearParam] && availableYears.length) {
  yearParam = availableYears[availableYears.length - 1];
}
const monthsForYear = availability[yearParam]
  ? engMonthsInOrder.filter(m => availability[yearParam].has(m))
  : [];
if (monthsForYear.length && !monthsForYear.includes(monthParam)) {
  monthParam = monthsForYear[0];
}

const monthName = monthMap[monthParam] || monthMap[now.toLocaleString('en-US', { month:'long' }).toLowerCase()];
const reportLabel = `${monthName} ${yearParam}`;

// ---- format & exclusions ----
const nf = new Intl.NumberFormat('ru-RU', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
const exclude = new Set(data.exclude_operations || []);   // можно оставить, он не мешает

// ---- АГРЕГАТЫ ТОЛЬКО ИЗ СЫРЬЯ ----
// helper: фильтр по exclude
const notExcluded = r => !exclude.has(r.operation);

// ✳️ расходы — из сырых расходов (если хочешь только наличные, добавь .filter(r => r.cash_type === 'Наличные'))
const expRows = rawExp
  .filter(notExcluded)
  .filter(r => r.cash_type === 'Наличные');

// ✳️ доходы — ТОЛЬКО НАЛИЧНЫЕ из сырых доходов, как ты хотел
const revRowsCash = rawRev
  .filter(notExcluded)
  .filter(r => r.cash_type === 'Наличные');

// агрегируем по операции
function aggregateByOperation(rows, kind) {
  const acc = rows.reduce((map, r) => {
    const op = r.operation || 'Без операции';
    if (!map[op]) {
      map[op] = {
        operation: op,
        kind,
        total_sum: 0,
        count: 0,
      };
    }
    map[op].total_sum += Number(r.total_sum || 0);
    map[op].count += 1;
    return map;
  }, {});
  return Object.values(acc).map(r => ({
    ...r,
    total_sum_fmt: nf.format(r.total_sum),
  }));
}

const expendituresAgg = aggregateByOperation(expRows, 'expenditure');
const revenuesAgg     = aggregateByOperation(revRowsCash, 'revenue');   // ★ только cash

const expenditure_total = expendituresAgg.reduce((s,x) => s + Number(x.total_sum || 0), 0);
const revenue_total     = revenuesAgg.reduce((s,x) => s + Number(x.total_sum || 0), 0);
const net_total         = revenue_total - expenditure_total;

// ---- FULL operations (тоже только из сырья) ----
function normalize(rows, kind) {
  return rows
    .filter(r => !exclude.has(r.operation))
    // если надо показывать в таблице только Наличные — оставь эту строку
    // если нужно ВСЁ — просто удали её
    .filter(r => r.cash_type === 'Наличные')
    .map(r => ({
      kind,                                // 'expenditure' | 'revenue'
      id: r.id || '',
      date: r.date || '',
      operation: r.operation || '',
      cash_type: r.cash_type || '',
      counterparty: r.counterparty || '',
      employee: r.employee || '',
      total_sum: Number(r.total_sum || 0),
      total_sum_fmt: nf.format(Number(r.total_sum || 0)),
      comment: r.comment || '',
      account: r.account || '',
      confirmed: r.confirmed === true ? 'да' : (r.confirmed === false ? 'нет' : ''),
      unit: r.unit || '',
      organization: r.organization || '',
    }));
}

const fullOps = [
  ...normalize(rawExp, 'expenditure'),
  ...normalize(rawRev, 'revenue'),
];

// optional: sort by date then id
fullOps.sort((a, b) => (a.date || '').localeCompare(b.date || '') || (a.id || '').localeCompare(b.id || ''));

// ---- HTML helpers ----
const rowAgg = (r) => `
  <tr>
    <td class="op">${r.operation}</td>
    <td><span class="badge ${r.kind==='revenue'?'rev':'exp'}">${r.kind==='revenue'?'Доход':'Расход'}</span></td>
    <td class="num">${r.total_sum_fmt || nf.format(Number(r.total_sum||0))}</td>
    <td class="num">${r.count ?? 0}</td>
  </tr>
`;

const rowFull = (r) => `
  <tr>
    <td class="num">${r.date}</td>
    <td>${r.id}</td>
    <td class="op">${r.operation}</td>
    <td><span class="badge ${r.kind==='revenue'?'rev':'exp'}">${r.kind==='revenue'?'Доход':'Расход'}</span></td>
    <td>${r.cash_type}</td>
    <td>${r.counterparty}</td>
    <td class="num">${r.total_sum_fmt}</td>
    <td>${r.employee}</td>
    <td>${r.comment}</td>
  </tr>
`;

// ---- build HTML ----
const html = `
<!doctype html>
<html lang="ru">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<title>Финансовая сводка — ${reportLabel}</title>
<style>
  :root{--bg:#0b1220;--card:#111a2b;--muted:#6b7a99;--text:#e6edf7;--rev:#2db47d;--exp:#e65757;--border:#1e2a44;}
  *{box-sizing:border-box}
  body{margin:0;background:var(--bg);color:var(--text);font:14px/1.45 system-ui,-apple-system,Segoe UI,Roboto,Ubuntu,Cantarell,Noto Sans,sans-serif;padding:24px}
  .wrap{max-width:1200px;margin:0 auto}
  h1{font-size:22px;margin:0 0 6px}
  .sub{color:var(--muted);margin:0 0 18px}
  .controls{margin-bottom:16px;display:flex;gap:8px;align-items:center;flex-wrap:wrap}
  select{padding:6px 10px;border-radius:8px;border:1px solid var(--border);background:var(--card);color:var(--text);font-size:14px}
  button{padding:6px 12px;border:none;border-radius:8px;background:var(--rev);color:#fff;font-weight:600;cursor:pointer}
  .grid{display:grid;grid-template-columns:1fr 1fr;gap:16px;margin-top:16px}
  .card{background:var(--card);border:1px solid var(--border);border-radius:14px;padding:16px;box-shadow:0 6px 18px rgba(0,0,0,.25)}
  .kpis{display:grid;grid-template-columns:1fr 1fr 1fr;gap:12px}
  .kpi{padding:14px;border:1px solid var(--border);border-radius:12px;background:linear-gradient(180deg,rgba(58,122,254,.08),transparent)}
  .kpi h3{margin:0 0 8px;font-size:12px;color:var(--muted);text-transform:uppercase;letter-spacing:.06em}
  .kpi .val{font-size:20px;font-weight:700}
  .table{width:100%;border-collapse:collapse;margin-top:8px}
  .table th,.table td{padding:8px 10px;border-bottom:1px solid var(--border);text-align:left;vertical-align:top}
  .table th{font-size:12px;color:var(--muted);text-transform:uppercase;letter-spacing:.06em;position:sticky;top:0;background:var(--card);z-index:1}
  .table td.op{font-weight:600}
  .table td.num{text-align:right;font-variant-numeric:tabular-nums}
  .badge{padding:4px 8px;border-radius:999px;font-size:12px;border:1px solid var(--border);background:#15213a;white-space:nowrap}
  .badge.rev{border-color:rgba(45,180,125,.35);color:#b9f2d9;background:rgba(45,180,125,.08)}
  .badge.exp{border-color:rgba(230,87,87,.35);color:#ffd3d3;background:rgba(230,87,87,.08)}
  .muted{color:var(--muted)}
  .scroll{max-height:60vh;overflow:auto;border:1px solid var(--border);border-radius:12px}
  @media (max-width:1100px){.grid{grid-template-columns:1fr}}
</style>
</head>
<body>
  <div class="wrap">
    <h1>Финансовая сводка — ${reportLabel}</h1>
    <p class="sub muted">Источник файла: <strong>${src.filename || data.filename || 'не указано'}</strong></p>

    <div class="controls">
      <label>Год:
        <select id="year"></select>
      </label>
      <label>Месяц:
        <select id="month"></select>
      </label>
      <button id="showBtn">Показать</button>
      <span class="muted" style="margin-left:8px">(доступны только периоды из списка)</span>
    </div>

    <script>
      const availability = ${JSON.stringify(
        Object.fromEntries(Object.entries(availability).map(([y,set]) => [y, Array.from(set)]))
      )};
      const monthMap = ${JSON.stringify(monthMap)};
      const order = ${JSON.stringify(engMonthsInOrder)};
      const initialYear = ${JSON.stringify(yearParam)};
      const initialMonth = ${JSON.stringify(monthParam)};

      const yearSel = document.getElementById('year');
      const monthSel = document.getElementById('month');

      function fillYears() {
        const years = Object.keys(availability).sort();
        yearSel.innerHTML = years.map(y => '<option value="'+y+'">'+y+'</option>').join('');
        if (years.includes(initialYear)) yearSel.value = initialYear;
        else yearSel.value = years[years.length-1] || '';
      }

      function fillMonths(forYear, preselectMonth) {
        const avail = new Set(availability[forYear] || []);
        const months = order.filter(m => avail.has(m));
        monthSel.innerHTML = months.map(m => '<option value="'+m+'">'+monthMap[m]+'</option>').join('');
        if (months.includes(preselectMonth)) monthSel.value = preselectMonth;
        else if (months.length) monthSel.value = months[0];
        else monthSel.value = '';
      }

      fillYears();
      fillMonths(yearSel.value, initialMonth);

      yearSel.addEventListener('change', () => {
        fillMonths(yearSel.value, monthSel.value);
      });

      document.getElementById('showBtn').addEventListener('click', () => {
        const m = monthSel.value;
        const y = yearSel.value;
        const base = window.location.href.split('?')[0];
        window.location.href = base + '?month=' + m + '&year=' + y;
      });
    </script>

    <div class="kpis">
      <div class="kpi"><h3>Доходы (наличные)</h3><div class="val">${nf.format(revenue_total)}</div></div>
      <div class="kpi"><h3>Расходы</h3><div class="val">${nf.format(expenditure_total)}</div></div>
      <div class="kpi"><h3>Итог (Доходы − Расходы)</h3><div class="val" style="color:${net_total>=0?'var(--rev)':'var(--exp)'}">${nf.format(net_total)}</div></div>
    </div>

    <div class="grid">
      <div class="card">
        <h2 style="margin:0 0 8px">Доходы по операциям (наличные)</h2>
        <div class="scroll">
          <table class="table">
            <thead><tr><th>Операция</th><th>Тип</th><th>Сумма</th><th>Кол-во</th></tr></thead>
            <tbody>${revenuesAgg.map(rowAgg).join('')}</tbody>
          </table>
        </div>
      </div>

      <div class="card">
        <h2 style="margin:0 0 8px">Расходы по операциям</h2>
        <div class="scroll">
          <table class="table">
            <thead><tr><th>Операция</th><th>Тип</th><th>Сумма</th><th>Кол-во</th></tr></thead>
            <tbody>${expendituresAgg.map(rowAgg).join('')}</tbody>
          </table>
        </div>
      </div>

      <div class="card" style="grid-column:1/-1">
        <h2 style="margin:0 8px 8px 0">Все операции</h2>
        <div class="scroll">
          <table class="table">
            <thead>
              <tr>
                <th>Дата</th>
                <th>ID</th>
                <th>Операция</th>
                <th>Тип</th>
                <th>Тип оплаты</th>
                <th>Контрагент</th>
                <th>Сумма</th>
                <th>Сотрудник</th>
                <th>Комментарий</th>
              </tr>
            </thead>
            <tbody>
              ${fullOps.map(rowFull).join('')}
            </tbody>
          </table>
        </div>
      </div>
    </div>

    ${exclude.size ? `<p class="muted" style="margin-top:24px;font-size:12px">Исключены операции: ${Array.from(exclude).join(', ')}</p>` : ''}
  </div>
</body>
</html>
`;

// Return HTML to webhook responder
return [{ json: { html, month: monthName, year: yearParam } }];
